query:
CREATE TABLE IF NOT EXISTS `orders` (`id` int AUTO_INCREMENT NOT NULL, `buyerId` int NOT NULL, `sellerId` int NOT NULL, `productId` int NOT NULL, `quantity` int NOT NULL DEFAULT 1, `totalAmount` decimal(10,2) NOT NULL, `status` enum('pending','paid','shipped','delivered','cancelled','refunded') NOT NULL DEFAULT 'pending', `stripeSessionId` varchar(255), `stripePaymentIntentId` varchar(255), `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `orders_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `otp_tokens` (`id` int AUTO_INCREMENT NOT NULL, `userId` int NOT NULL, `email` varchar(320) NOT NULL, `code` varchar(8) NOT NULL, `type` enum('email_verify','password_reset') NOT NULL, `expiresAt` timestamp NOT NULL, `used` boolean NOT NULL DEFAULT false, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `otp_tokens_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `products` (`id` int AUTO_INCREMENT NOT NULL, `sellerId` int NOT NULL, `categoryId` int, `name` varchar(255) NOT NULL, `description` text, `price` decimal(10,2) NOT NULL, `stock` int NOT NULL DEFAULT 0, `images` json DEFAULT ('[]'), `status` enum('active','inactive') NOT NULL DEFAULT 'active', `featured` boolean NOT NULL DEFAULT false, `salesCount` int NOT NULL DEFAULT 0, `viewCount` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `products_id` PRIMARY KEY(`id`))

